            was_audit_in_progress = _AUDIT_IN_PROGRESS_GLOBAL
            _AUDIT_IN_PROGRESS_GLOBAL = False

            if _AUDIT_LOCK_FILE and _AUDIT_LOCK_FILE.exists():
                try:
