        results = []
        for _ in range(200):
            result = scheduler_manager.select_task_for_reminder(tasks)
            results.append(result["priority"])

        # Critical tasks should be selected most often (3.0x weight)
        critical_count = results.count("critical")
        high_count = results.count("high")
        medium_count = results.count("medium")
        low_count = results.count("low")
        none_count = results.count("none")

        # Verify priority weighting is working (critical should be most frequent)
        # Use lenient assertions for probabilistic tests (allow variance due to randomness)
        assert (
            critical_count > medium_count
        ), f"Critical ({critical_count}) should be more frequent than medium ({medium_count})"
        assert (
            critical_count > low_count
        ), f"Critical ({critical_count}) should be more frequent than low ({low_count})"
        assert (
            critical_count > none_count
        ), f"Critical ({critical_count}) should be more frequent than none ({none_count})"
        # High should generally be more frequent than low, but allow significant variance for probabilistic test
        # With 200 iterations, allow up to 15% variance (30 iterations) to account for randomness
        assert (
            high_count >= low_count - 30
        ), f"High ({high_count}) should be reasonably close to or greater than low ({low_count})"
        assert (
            high_count >= none_count - 30
        ), f"High ({high_count}) should be reasonably close to or greater than none ({none_count})"

