    """Make archive_old_messages use a fixed UTC 'now' (cutoff math)."""

    class _PatchedDatetime:
        min = datetime.min
        max = datetime.max

        @staticmethod
        def now(tz=None):
            return fixed_now

    monkeypatch.setattr("core.message_management.datetime", _PatchedDatetime)


