        assert archived["messages"][0]["message_id"] == "old"

        active = json.loads(sent.read_text(encoding="utf-8"))
        assert len(active["messages"]) == 1
        assert active["messages"][0]["message_id"] == "new"
        assert active["metadata"]["total_messages"] == 1

